import React from "react";
import "./nav.css";

function Nav() {
  return (
    <div className="nav">
      <img
        src="https://i.ibb.co/r5krrdz/logo.png"
        alt="logo"
        className="nav__logo"
      />
      <img src="/images/users/4.png" alt="avatar" className="nav__avatar" />
    </div>
  );
}

export default Nav;
